using Smoower.Minified.EFCore;namespace Smoower.Minified.Tests;public class SyncExtensionsTests{private static TestDb Seed(string name){var db = TestDbFactory.Create(name);db.Things.AddRange(new Thing { Name = "a", Rank = 1 }, new Thing { Name = "b", Rank = 2 });db.SaveChanges();return db;}[F]public void QuerySyncTerminators_Work(){var db = Seed(nameof(QuerySyncTerminators_Work));db.Things.lstS().Count.eq(2);db.Things.w(t => t.Rank == 1).oneS()!.Name.eq("a");db.Things.w(t => t.Rank == 2).singleS()!.Name.eq("b");db.Things.anyS().tru();db.Things.cntS().eq(2);}[F]public void AddS_PersistsAndReturns(){var db = TestDbFactory.Create(nameof(AddS_PersistsAndReturns));var saved = db.addS(new Thing { Name = "x", Rank = 1 });(saved.Id > 0).tru();db.Things.idS(saved.Id)!.Name.eq("x");}[F]public void UpdS_And_DelS_Work(){var db = TestDbFactory.Create(nameof(UpdS_And_DelS_Work));var saved = db.addS(new Thing { Name = "x", Rank = 1 });saved.Name = "y";db.updS(saved);db.Things.idS(saved.Id)!.Name.eq("y");db.delS(saved);db.Things.cntS().eq(0);}[F]public void SaveS_ReturnsAffectedCount(){var db = TestDbFactory.Create(nameof(SaveS_ReturnsAffectedCount));db.Things.Add(new Thing { Name = "x", Rank = 1 });db.saveS().eq(1);}}
